import{_ as a,o,c as l,ag as i}from"./chunks/framework.DTiDeF2Q.js";const u=JSON.parse('{"title":"关于 Dotfiles (ZH)","titleTemplate":":title","description":"下一代 shell 配置。高性能、安全且原生支持 AI。由 Chezmoi 管理。","frontmatter":{"title":"关于 Dotfiles","description":"下一代 shell 配置。高性能、安全且原生支持 AI。由 Chezmoi 管理。","lang":"zh-CN","author":"Sebastien Rousseau","lastUpdated":true,"image":"/logo.png","imageAlt":"关于 Dotfiles preview","canonical":"/zh/about/","robots":"index, follow","draft":false,"noindex":false,"sitemap":true,"breadcrumbTitle":"关于 Dotfiles","pageType":"docs","schemaType":"WebPage","metaTitle":"关于 Dotfiles - Dotfiles (CN)","permalink":"/zh/about/","meta":[{"name":"keywords","content":"chezmoi, dotfiles, 配置, 自动化, macos, linux, rust, zellij, shell, 终端"},{"name":"twitter:card","content":"summary"},{"name":"twitter:description","content":"下一代 shell 配置。高性能、安全且原生支持 AI。由 Chezmoi 管理。"},{"name":"twitter:title","content":"关于 Dotfiles"},{"name":"og:title","content":"关于 Dotfiles"},{"name":"og:description","content":"下一代 shell 配置。高性能、安全且原生支持 AI。由 Chezmoi 管理。"},{"name":"og:image:alt","content":"Dotfiles - 为你的 Shell 生活精心设计"},{"name":"og:locale","content":"zh_CN"}]},"headers":[],"relativePath":"zh/about/index.md","filePath":"zh/about/index.md","lastUpdated":1773010926000}'),t={name:"zh/about/index.md"};function s(d,e,n,c,r,h){return o(),l("div",null,[...e[0]||(e[0]=[i(`<h1 id="关于-dotfiles" tabindex="-1">关于 Dotfiles <a class="header-anchor" href="#关于-dotfiles" aria-label="Permalink to &quot;关于 Dotfiles&quot;">​</a></h1><p>Shell 配置的现代标准。基于 <strong>Chezmoi</strong> 构建，用于安全的跨平台环境管理。</p><h2 id="发现" tabindex="-1">发现 <a class="header-anchor" href="#发现" aria-label="Permalink to &quot;发现&quot;">​</a></h2><p>Dotfiles v0.2.495 将你的终端转变为强大的统一工作空间。与依赖复杂 Makefile 或符号链接脚本的旧式 dotfiles 不同，Dotfiles 使用基于模板的方法，原子化、快速且可重现。</p><h3 id="新功能" tabindex="-1">新功能 <a class="header-anchor" href="#新功能" aria-label="Permalink to &quot;新功能&quot;">​</a></h3><ul><li><strong>现代核心</strong> — 高性能 Rust 替代品取代传统 Unix 工具： <ul><li><strong>Atuin</strong> 用于 shell 历史</li><li><strong>Yazi</strong> 用于文件管理</li><li><strong>Zellij</strong> 用于终端复用</li><li><strong>Ghostty</strong> GPU 加速终端</li><li><strong>NeoVim</strong> 用于现代编辑</li></ul></li><li><strong>原生安全</strong> — 完全原生 SSH 签名，无需第三方代理</li><li><strong>交互模式</strong> — 新的 <code>dot learn</code> 命令引导你了解各项功能</li></ul><h2 id="开始使用" tabindex="-1">开始使用 <a class="header-anchor" href="#开始使用" aria-label="Permalink to &quot;开始使用&quot;">​</a></h2><h3 id="要求" tabindex="-1">要求 <a class="header-anchor" href="#要求" aria-label="Permalink to &quot;要求&quot;">​</a></h3><ul><li><strong>macOS</strong>、<strong>Linux (Ubuntu/Debian)</strong> 或 <strong>Windows (WSL)</strong></li><li><strong>Curl</strong> 和 <strong>Git</strong></li><li><strong>Chezmoi</strong>（自动安装）</li><li><strong>Nerd Font</strong>（用于终端图标）</li></ul><h3 id="安装" tabindex="-1">安装 <a class="header-anchor" href="#安装" aria-label="Permalink to &quot;安装&quot;">​</a></h3><p>运行单个命令安装整个套件：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">bash</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -c</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;$(</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -fsSL</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://raw.githubusercontent.com/sebastienrousseau/dotfiles/master/install.sh)&quot;</span></span></code></pre></div><p>安装程序将：</p><ol><li>安装 <code>chezmoi</code> 二进制文件</li><li>克隆仓库</li><li>通过 Homebrew (macOS) 或 Apt (Linux) 安装所需软件包</li><li>应用你的配置</li></ol><h3 id="探索" tabindex="-1">探索 <a class="header-anchor" href="#探索" aria-label="Permalink to &quot;探索&quot;">​</a></h3><p>安装后，重启终端并运行：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">dot</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> learn</span></span></code></pre></div><p>这将启动新环境的交互式导览。</p><h2 id="自定义" tabindex="-1">自定义 <a class="header-anchor" href="#自定义" aria-label="Permalink to &quot;自定义&quot;">​</a></h2><p>你的配置位于 <code>~/.local/share/chezmoi</code>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>~/.local/share/chezmoi</span></span>
<span class="line"><span>├── dot_zshenv              # Shell 入口点</span></span>
<span class="line"><span>├── dot_config/             # XDG 基础配置 (~/.config)</span></span>
<span class="line"><span>│   ├── atuin/              # Shell 历史</span></span>
<span class="line"><span>│   ├── ghostty/            # 终端模拟器</span></span>
<span class="line"><span>│   ├── git/                # Git 配置</span></span>
<span class="line"><span>│   ├── yazi/               # 文件管理器</span></span>
<span class="line"><span>│   ├── zellij/             # 终端复用器</span></span>
<span class="line"><span>│   ├── zsh/                # Zsh 配置</span></span>
<span class="line"><span>│   └── shell/              # 共享别名和路径</span></span>
<span class="line"><span>├── provision/              # 生命周期脚本</span></span>
<span class="line"><span>├── install.sh              # 通用安装程序</span></span>
<span class="line"><span>└── docs/                   # 文档</span></span></code></pre></div><h2 id="核心命令" tabindex="-1">核心命令 <a class="header-anchor" href="#核心命令" aria-label="Permalink to &quot;核心命令&quot;">​</a></h2><p><code>dot</code> CLI 提供 53 个按类别组织的命令。</p><h3 id="核心" tabindex="-1">核心 <a class="header-anchor" href="#核心" aria-label="Permalink to &quot;核心&quot;">​</a></h3><ul><li><code>dot apply</code> — 应用配置更改.</li><li><code>dot sync</code> — 拉取最新仓库状态并应用.</li><li><code>dot update</code> — 更新仓库并预热缓存.</li><li><code>dot add</code> — 将新文件添加到 Chezmoi 源.</li><li><code>dot diff</code> — 显示应用前的待处理更改.</li><li><code>dot status</code> — 显示受管文件的状态.</li><li><code>dot remove</code> — 取消管理文件并删除源条目.</li><li><code>dot cd</code> — 在 Chezmoi 源目录中打开 Shell.</li><li><code>dot edit</code> — 在编辑器中打开受管文件.</li><li><code>dot clean-cache</code> — 清除临时缓存.</li><li><code>dot prewarm</code> — 预填充缓存以加快 Shell 启动.</li></ul><h3 id="诊断" tabindex="-1">诊断 <a class="header-anchor" href="#诊断" aria-label="Permalink to &quot;诊断&quot;">​</a></h3><ul><li><code>dot doctor</code> — 验证路径、工具和 Shell 状态.</li><li><code>dot heal</code> — 自动修复缺失或损坏的状态.</li><li><code>dot health</code> — 运行轻量级健康探测.</li><li><code>dot verify</code> — 根据源检查文件完整性.</li><li><code>dot scorecard</code> — 输出配置质量评分.</li><li><code>dot snapshot</code> — 捕获当前状态以供后续比较.</li><li><code>dot smoke-test</code> — 端到端验证核心工具链.</li><li><code>dot chaos</code> — 注入故障以测试自我修复.</li><li><code>dot bundle</code> — 导出可移植的配置包.</li><li><code>dot rollback</code> — 回滚到之前的快照.</li><li><code>dot drift</code> — 检测受管文件的意外更改.</li><li><code>dot history</code> — 显示 apply/sync 历史日志.</li><li><code>dot benchmark</code> — 测量 Shell 启动时间.</li><li><code>dot perf</code> — 分析 Shell 初始化缓慢问题.</li></ul><h3 id="外观" tabindex="-1">外观 <a class="header-anchor" href="#外观" aria-label="Permalink to &quot;外观&quot;">​</a></h3><ul><li><code>dot theme</code> — 切换终端配色方案.</li><li><code>dot wallpaper</code> — 设置桌面壁纸（macOS）.</li><li><code>dot fonts</code> — 安装或更新 Nerd Fonts.</li><li><code>dot tune</code> — 调整界面密度和提示符样式.</li></ul><h3 id="安全" tabindex="-1">安全 <a class="header-anchor" href="#安全" aria-label="Permalink to &quot;安全&quot;">​</a></h3><ul><li><code>dot backup</code> — 创建加密的配置备份.</li><li><code>dot encrypt-check</code> — 验证静态密钥加密.</li><li><code>dot firewall</code> — 配置主机防火墙规则.</li><li><code>dot telemetry</code> — 控制匿名使用遥测.</li><li><code>dot dns-doh</code> — 启用 DNS-over-HTTPS.</li><li><code>dot lock-screen</code> — 立即锁定屏幕.</li><li><code>dot usb-safety</code> — 限制 USB 大容量存储自动挂载.</li></ul><h3 id="密钥" tabindex="-1">密钥 <a class="header-anchor" href="#密钥" aria-label="Permalink to &quot;密钥&quot;">​</a></h3><ul><li><code>dot secrets-init</code> — 初始化密钥后端（age / GPG）.</li><li><code>dot secrets</code> — 列出加密的密钥条目.</li><li><code>dot secrets-create</code> — 创建新的加密密钥.</li><li><code>dot ssh-key</code> — 生成或轮换 SSH 密钥对.</li><li><code>dot ssh-cert</code> — 从 CA 请求 SSH 证书.</li></ul><h3 id="ai" tabindex="-1">AI <a class="header-anchor" href="#ai" aria-label="Permalink to &quot;AI&quot;">​</a></h3><ul><li><code>dot ai</code> — 打开交互式 AI 助手会话.</li><li><code>dot ai-setup</code> — 配置 AI 提供商的 API 密钥.</li><li><code>dot ai-query</code> — 向 AI 模型发送一次性提示.</li><li>AI 工具包装器: <code>cl</code>, <code>gemini</code>, <code>kiro</code>, <code>sgpt</code>, <code>ollama</code>, <code>opencode</code>, <code>aider</code>.</li></ul><h3 id="工具" tabindex="-1">工具 <a class="header-anchor" href="#工具" aria-label="Permalink to &quot;工具&quot;">​</a></h3><ul><li><code>dot tools</code> — 列出捆绑的 CLI 替代工具及其状态.</li><li><code>dot new</code> — 创建新的别名或函数文件.</li><li><code>dot sandbox</code> — 打开一次性沙盒 Shell.</li><li><code>dot keys</code> — 显示当前键绑定.</li><li><code>dot learn</code> — 启动交互式教程.</li></ul><h3 id="元信息" tabindex="-1">元信息 <a class="header-anchor" href="#元信息" aria-label="Permalink to &quot;元信息&quot;">​</a></h3><ul><li><code>dot upgrade</code> — 将 Dotfiles 升级到最新版本.</li><li><code>dot packages</code> — 列出 Dotfiles 管理的已安装包.</li><li><code>dot version</code> / <code>dot help</code> — 显示版本或使用信息</li></ul><h2 id="贡献" tabindex="-1">贡献 <a class="header-anchor" href="#贡献" aria-label="Permalink to &quot;贡献&quot;">​</a></h2><p>加入社区。查看我们的<a href="https://github.com/sebastienrousseau/dotfiles/blob/master/.github/CODE-OF-CONDUCT.md" target="_blank" rel="noreferrer">行为准则</a>和<a href="https://github.com/sebastienrousseau/dotfiles/blob/master/.github/CONTRIBUTING.md" target="_blank" rel="noreferrer">贡献指南</a>。</p>`,41)])])}const b=a(t,[["render",s]]);export{u as __pageData,b as default};
